define([
  "jquery",
  "base/js/events",
  "base/js/namespace",
  "base/js/utils"
], function($, events, Jupyter, utils) {
  "use strict";

  if ($(".rqtabs").length > 0 && $(".rqtabs .used").length === 0) {
    var $memoryLiEle = $(
      '<li class="js-memory-container memory-container">' +
        '<span class="used js-used"></span>' +
        '<span class="total js-total">共有 <span class="js-total-size">6G</span> 内存供您使用</span>' +
        "</li>"
    );
    $(".rqtabs .nav-tabs").append($memoryLiEle);
    var outerWidth = $(".js-total").outerWidth();
    $.get("api/rqinfo/memory").then(function(res) {
      var width = (res.memory / res.total) * outerWidth;
      $(".js-used").css("width", width);
      $(".js-total-size").text(getMemory(res.total));
    });
  }

  var locationPath = Jupyter.login_widget.base_url + "/api/rqinfo/memory";
  if (
    $("#maintoolbar").length > 0 &&
    $("#maintoolbar .js-memory-total").length === 0
  ) {
    console.log("define & notebook_loaded.Notebook");
    var $memoryDivEle = $(
      '<div class="btn-group memory-total js-memory-total">' +
        "共有 <span class='js-memory-total-size'>6G</span> 内存供您使用" +
        '<div class="memory-used js-memory-used"></div></div>'
    );
    Jupyter.toolbar.element.append($memoryDivEle);
    var outerWidth = $(".js-memory-total").outerWidth();
    $.get(locationPath).then(function(res) {
      var width = (res.memory / res.total) * outerWidth;
      $(".js-memory-used").css("width", width);
      $(".js-memory-total-size").text(getMemory(res.total));
    });
  }

  setInterval(function() {
    $.get(locationPath).then(function(res) {
      var width = (res.memory / res.total) * outerWidth;
      locationPath === Jupyter.login_widget.base_url + "/api/rqinfo/memory"
        ? $(".js-used").css("width", width)
        : $(".js-memory-used").css("width", width);
      locationPath === Jupyter.login_widget.base_url + "/api/rqinfo/memory"
        ? $(".js-total-size").text(getMemory(res.total))
        : $(".js-memory-total-size").text(getMemory(res.total));
    });
  }, 60000);

  function getMemory(num) {
    return parseInt(num / 1024 / 1024 / 1024) + "G";
  }

  function deleteAllCookies() {
    var cookies = document.cookie.split(";");

    for (var i = 0; i < cookies.length; i++) {
      var cookie = cookies[i];
      var eqPos = cookie.indexOf("=");
      var name = eqPos > -1 ? cookie.substr(0, eqPos) : cookie;
      document.cookie = name + "=;expires=Thu, 01 Jan 1970 00:00:00 GMT";
    }
  }

  $("#rq_logout").click(function() {
    var user_id = location.pathname
      .split("/")
      .filter(function(item) {
        return item.indexOf("user_") > -1;
      })
      .concat([""])[0]
      .split("_")[1];
    $.ajax({
      url: "/api/user/logout.do?user_id=" + user_id,
      method: "get",
      success: function(res) {
        $.ajax({
          url: "/community/logout",
          method: "post",
          data: {
            password: res.token
          }
        });
        deleteAllCookies();
        $.ajax({
          url: utils.url_join_encode(utils.get_body_data("baseUrl"), "logout"),
          method: "get",
          success: function() {
            location.href = "/";
          }
        });
      }
    });
  });

  $.get(Jupyter.login_widget.base_url + "/api/notebook/sid").then(function(
    res
  ) {});

